function extractTableNames(sql) {
    if (!sql) return [];
    // Matches FROM or JOIN followed by table names, ignoring schemas
    const regex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
    const tables = [];
    let match;
    while ((match = regex.exec(sql)) !== null) {
        if (match[1] && !tables.includes(match[1])) tables.push(match[1]);
    }
    return tables;
}

